import{_ as l,o,c as i,ae as a}from"./chunks/framework.Czhw_PXq.js";const q=JSON.parse('{"title":"李录价值投资核心演讲：价值投资在中国的展望 | 为什么中国能实现价值投资？","description":"深度解读李录2015年北大光华管理学院演讲：价值投资的四大核心理念、资产管理行业的道德底线、为什么中国能实现价值投资、散户市场带来的独特机会。","frontmatter":{"title":"李录价值投资核心演讲：价值投资在中国的展望 | 为什么中国能实现价值投资？","description":"深度解读李录2015年北大光华管理学院演讲：价值投资的四大核心理念、资产管理行业的道德底线、为什么中国能实现价值投资、散户市场带来的独特机会。","pubDate":"2026-05-17","heroImage":"/images/lilu-book/value-investing-china-cover.jpg","keywords":["李录","价值投资","中国价值投资","巴菲特","安全边际","能力圈","受托人责任","股市投资"],"author":"黄秋钊","category":"读书笔记","tags":["李录","价值投资","投资理念","中国股市","巴菲特","安全边际"],"series":"《文明、现代化、价值投资与中国》深度解读","seriesOrder":3},"headers":[],"relativePath":"posts/lilu-ch03-value-investing-china.md","filePath":"posts/lilu-ch03-value-investing-china.md"}'),r={name:"posts/lilu-ch03-value-investing-china.md"};function e(n,t,u,s,d,p){return o(),i("div",null,[...t[0]||(t[0]=[a('<h1 id="价值投资在中国的展望-为什么中国能实现价值投资" tabindex="-1">价值投资在中国的展望：为什么中国能实现价值投资？ <a class="header-anchor" href="#价值投资在中国的展望-为什么中国能实现价值投资" aria-label="Permalink to &quot;价值投资在中国的展望：为什么中国能实现价值投资？&quot;">​</a></h1><blockquote><p>&quot;价值投资不仅在中国可以被应用，甚至中国目前不成熟的阶段使价值投资人在中国具备更多的优势。&quot; —— 李录（2015年北大光华管理学院演讲）</p></blockquote><h2 id="引言-一堂价值千金的投资课" tabindex="-1">引言：一堂价值千金的投资课 <a class="header-anchor" href="#引言-一堂价值千金的投资课" aria-label="Permalink to &quot;引言：一堂价值千金的投资课&quot;">​</a></h2><p>2015年10月，李录在北京大学光华管理学院发表了这篇演讲。</p><p>当时，A股刚刚经历了一轮惊心动魄的牛熊转换——从2014年底的2000多点暴涨到2015年6月的5178点，再到8月底跌回2850点。无数散户在这场波动中损失惨重，&quot;价值投资不适合中国&quot;的声音再次响起。</p><p>就在这样的背景下，李录系统地阐述了：</p><ul><li>资产管理行业的本质和道德要求</li><li>为什么股票是长期最好的投资标的</li><li>价值投资的四大核心理念</li><li>为什么中国能实现价值投资</li></ul><p>这篇演讲不仅是对价值投资的系统阐述，更是一位投资大师对年轻学子的殷切期望。</p><h2 id="第一部分-资产管理行业的本质与道德底线" tabindex="-1">第一部分：资产管理行业的本质与道德底线 <a class="header-anchor" href="#第一部分-资产管理行业的本质与道德底线" aria-label="Permalink to &quot;第一部分：资产管理行业的本质与道德底线&quot;">​</a></h2><h3 id="行业的两个独特特点" tabindex="-1">行业的两个独特特点 <a class="header-anchor" href="#行业的两个独特特点" aria-label="Permalink to &quot;行业的两个独特特点&quot;">​</a></h3><p>李录指出，资产管理行业与其他服务业相比有两个根本不同：</p><p><strong>特点一：用户无法判断产品好坏</strong></p><table tabindex="0"><thead><tr><th>行业</th><th>用户如何判断</th></tr></thead><tbody><tr><td>汽车</td><td>开完就知道好坏</td></tr><tr><td>餐厅</td><td>吃完就知道好坏</td></tr><tr><td>酒店</td><td>住完就知道好坏</td></tr><tr><td>资产管理</td><td><strong>绝大多数时候无法判断</strong></td></tr></tbody></table><p>&quot;你给我一份业绩，如果只有一年两年的业绩，我完全没有办法判断这个基金经理到底是不是优秀。即便是5年、10年的业绩也没法判断。&quot;</p><p><strong>特点二：报酬与贡献脱节</strong></p><ul><li>行业报酬总体高于其他几乎所有行业</li><li>常常脱离对客户财富增长的贡献</li><li>真正为客户提供的服务非常有限</li><li>定价结构反映从业人员利益，很少反映客户利益</li></ul><p>&quot;不管你是不是真正为客户赚到了钱，结果无论怎样你都会收一笔钱。特别是私募，收费的比例更高，高到离谱。你赚钱时收钱，亏钱的时候也要收钱。&quot;</p><h3 id="两条牢不可破的道德底线" tabindex="-1">两条牢不可破的道德底线 <a class="header-anchor" href="#两条牢不可破的道德底线" aria-label="Permalink to &quot;两条牢不可破的道德底线&quot;">​</a></h3><p>基于以上特点，李录提出了进入这个行业必须遵守的两条道德底线：</p><p><strong>底线一：追求真知、智慧的道德责任</strong></p><blockquote><p>&quot;把对真知、智慧的追求当作是自己的道德责任，要有意识地杜绝一切屁股决定脑袋的理论。&quot;</p></blockquote><p>为什么重要？</p><ul><li>这个行业很复杂，似是而非的观点很多</li><li>这个行业不是精确的科学，包含很多判断</li><li>一旦进入职场，几乎所有理论都跟屁股和脑袋的关系紧密相连</li><li>如果思考得不深，很快就把自己的利益当作客户的利益</li></ul><p><strong>底线二：建立受托人责任（Fiduciary Duty）</strong></p><blockquote><p>&quot;客户给你的每一分钱，你都把它看作是自己的父母辛勤劳动、勤俭节省、积攒了一辈子、交到你手上去打理的钱。&quot;</p></blockquote><p>受托人责任的核心：</p><ul><li>钱虽然不多，但汇聚了一家人一生的辛苦节俭所得</li><li>这种责任感某种程度上是先天基因</li><li>没有这种基因的人，以后无论用什么方式，基本上都没有办法让他有</li></ul><p><strong>李录的警告：</strong></p><blockquote><p>&quot;如果没有这种基因，我劝大家一定不要进入这个行业。因为你进入这个行业一定会成为无数家庭财富的破坏者、终结者。&quot;</p></blockquote><h2 id="第二部分-200年数据揭示的财富真相" tabindex="-1">第二部分：200年数据揭示的财富真相 <a class="header-anchor" href="#第二部分-200年数据揭示的财富真相" aria-label="Permalink to &quot;第二部分：200年数据揭示的财富真相&quot;">​</a></h2><h3 id="美国200年大类资产表现" tabindex="-1">美国200年大类资产表现 <a class="header-anchor" href="#美国200年大类资产表现" aria-label="Permalink to &quot;美国200年大类资产表现&quot;">​</a></h3><p>李录引用了宾州大学沃顿商学院西格尔教授（Jeremy Siegel）的数据，回溯到1802年：</p><table tabindex="0"><thead><tr><th>资产类别</th><th>1802年1美元的购买力（200年后）</th><th>年化回报</th></tr></thead><tbody><tr><td>现金</td><td>0.05美元（丢失95%）</td><td>-1.4%（通胀）</td></tr><tr><td>黄金</td><td>3.12美元</td><td>0.5%</td></tr><tr><td>短期债券</td><td>275美元</td><td>2.7%</td></tr><tr><td>长期债券</td><td>1,600美元</td><td>3.5%</td></tr><tr><td><strong>股票</strong></td><td><strong>103万美元</strong></td><td><strong>6.7%</strong></td></tr></tbody></table><p><strong>股票的零头都大于其他大类资产！</strong></p><h3 id="为什么现金和股票差距如此巨大" tabindex="-1">为什么现金和股票差距如此巨大？ <a class="header-anchor" href="#为什么现金和股票差距如此巨大" aria-label="Permalink to &quot;为什么现金和股票差距如此巨大？&quot;">​</a></h3><p><strong>原因一：通货膨胀</strong></p><p>美国过去200年平均年化通胀约1.4%。</p><p>如果通货膨胀每年以1.4%的速度增长，200年后1块钱变成5分钱，丢失了95%的购买力。</p><p><strong>原因二：经济增长</strong></p><p>GDP在过去200年里大约增长了33,000多倍，年化约3%多。</p><p>股票代表市场里一定规模以上的公司，GDP的增长很大意义上是由这些公司销售额的增长决定的。</p><p><strong>净利润的增长超过销售额的增长</strong>，因为公司有相对固定的成本。当销售额以4-5%的名义速度增长时，净利润就会以6-7%的速度增长。</p><p>股票的价值核心是利润本身的增长反映到今天的价值。过去200年股票的平均市盈率在15倍左右，每股现金的收益就是15的倒数，差不多6.7%。</p><h3 id="人类16000年经济史的独特现象" tabindex="-1">人类16000年经济史的独特现象 <a class="header-anchor" href="#人类16000年经济史的独特现象" aria-label="Permalink to &quot;人类16000年经济史的独特现象&quot;">​</a></h3><p>李录展示了伊恩·莫里斯教授的数据，覆盖过去16000年：</p><p><strong>关键发现：</strong></p><ul><li>过去一万多年里，经济增长几乎是一条平线</li><li>农业文明时代，发展非常缓慢，经常呈现波浪式</li><li>冲顶之后就会滑落，有一个&quot;玻璃顶&quot;突破不了</li><li><strong>但在过去300年间，突然呈现巨幅增长</strong></li></ul><p>这就是3.0文明——现代科技和自由市场经济结合产生的独特现象。</p><p><strong>李录的总结：</strong></p><blockquote><p>&quot;这种一个经济能够长期持续以复利的方式来增长的现象，在人类16000年的记载里从来没有发生过，是非常现代的现象。&quot;</p></blockquote><h2 id="第三部分-价值投资的四大核心理念" tabindex="-1">第三部分：价值投资的四大核心理念 <a class="header-anchor" href="#第三部分-价值投资的四大核心理念" aria-label="Permalink to &quot;第三部分：价值投资的四大核心理念&quot;">​</a></h2><p>李录将价值投资归纳为四个核心理念：</p><h3 id="理念一-股票代表公司所有权" tabindex="-1">理念一：股票代表公司所有权 <a class="header-anchor" href="#理念一-股票代表公司所有权" aria-label="Permalink to &quot;理念一：股票代表公司所有权&quot;">​</a></h3><blockquote><p>&quot;股票不仅仅是可以买卖的证券，实际上代表的是对公司所有权的证书，是对公司的部分所有权。&quot;</p></blockquote><p><strong>为什么重要？</strong></p><ul><li>投资股票实际上是投资一个公司</li><li>公司随着GDP的增长，价值本身会被不断地创造</li><li>作为部分所有者，我们持有的价值也会随着公司价值的增长而增长</li><li><strong>这是可持续的&quot;正道&quot;</strong></li></ul><p><strong>正道 vs 邪道：</strong></p><ul><li>正道：你得到的东西是你应得的</li><li>邪道：通过零和游戏从别人口袋里掏钱</li></ul><h3 id="理念二-市场是为服务你而存在" tabindex="-1">理念二：市场是为服务你而存在 <a class="header-anchor" href="#理念二-市场是为服务你而存在" aria-label="Permalink to &quot;理念二：市场是为服务你而存在&quot;">​</a></h3><blockquote><p>&quot;市场的存在只是为你而服务的。能够给你提供机会，让你去购买所有权，也会给你个机会，在你很多年之后需要钱的时候，能够把它出让，变成现金。&quot;</p></blockquote><p><strong>关键洞察：</strong></p><ul><li>市场从来都不能告诉你真正的价值是什么</li><li>它只能告诉你价格是什么</li><li><strong>你不能把市场当作你的老师，你只能把它当作一个可以利用的工具</strong></li></ul><p>这与95%以上市场参与者的理解正好相反。</p><h3 id="理念三-安全边际" tabindex="-1">理念三：安全边际 <a class="header-anchor" href="#理念三-安全边际" aria-label="Permalink to &quot;理念三：安全边际&quot;">​</a></h3><blockquote><p>&quot;投资的本质是对未来进行预测，而预测得到的结果不可能百分之百准确，只能是从零到接近一百。那么当我们做判断的时候，就必须要预留很大的空间，叫安全边际。&quot;</p></blockquote><p><strong>安全边际的核心：</strong></p><ul><li>买入价格一定要大大低于公司的内在价值</li><li>如果预测是错误的，至少不会亏很多钱</li><li>如果预测是正确的，回报就会比别人高很多</li></ul><p><strong>为什么重要？</strong></p><p>即使你有80%、90%的把握，但因为不可能达到100%，当那10%、20%的可能性出现时，如果没有足够的安全边际，就会损失太多。</p><h3 id="理念四-能力圈" tabindex="-1">理念四：能力圈 <a class="header-anchor" href="#理念四-能力圈" aria-label="Permalink to &quot;理念四：能力圈&quot;">​</a></h3><p>这是巴菲特的独特贡献。</p><blockquote><p>&quot;投资人可以通过长期不懈的努力，真正建立起自己的能力圈，能够对某些公司、某些行业获得比几乎所有人更深的理解，而且能够对公司未来长期的表现，做出比所有其他人更准确的判断。&quot;</p></blockquote><p><strong>能力圈的关键：边界</strong></p><ul><li>没有边界的能力就不是真的能力</li><li>如果你有一个观点，你必须要能够告诉我这个观点不成立的条件</li><li>如果直接告诉我就是这么一个结论，那么这个结论一定是错误的</li></ul><p><strong>为什么能力圈重要？</strong></p><blockquote><p>&quot;市场存在的目的是什么？对于市场参与者而言，市场存在的目的就是发现人性的弱点。&quot;</p></blockquote><ul><li>你自己有哪些地方没有真正弄明白</li><li>你身上有什么样的心理、生理弱点</li><li>一定会在市场的某一种状态下暴露</li></ul><p><strong>真正的风险是什么？</strong></p><blockquote><p>&quot;这个风险不是股票价格的上上下下，而是资本永久性地丢失，这才是真正的风险。&quot;</p></blockquote><h2 id="第四部分-为什么价值投资是大道、正道" tabindex="-1">第四部分：为什么价值投资是大道、正道？ <a class="header-anchor" href="#第四部分-为什么价值投资是大道、正道" aria-label="Permalink to &quot;第四部分：为什么价值投资是大道、正道？&quot;">​</a></h2><h3 id="可持续性的标准" tabindex="-1">可持续性的标准 <a class="header-anchor" href="#可持续性的标准" aria-label="Permalink to &quot;可持续性的标准&quot;">​</a></h3><p>李录提出了一个判断可持续性的标准：</p><blockquote><p>&quot;什么东西可持续？可持续的东西都具有一个共同的特点，就是你得到的东西在所有其他人看来，都是你应得的东西，这就可持续了。&quot;</p></blockquote><p><strong>对比：</strong></p><table tabindex="0"><thead><tr><th>方式</th><th>是否可持续</th><th>原因</th></tr></thead><tbody><tr><td>价值投资</td><td>可持续</td><td>帮助公司增长，为客户创造价值，得到的是应得的</td></tr><tr><td>短期投机</td><td>不可持续</td><td>零和游戏，从别人口袋里掏钱</td></tr><tr><td>高收费基金</td><td>不可持续</td><td>赚钱时收钱，亏钱时也收钱，客户觉得不公平</td></tr></tbody></table><h3 id="为什么走大道的人少" tabindex="-1">为什么走大道的人少？ <a class="header-anchor" href="#为什么走大道的人少" aria-label="Permalink to &quot;为什么走大道的人少？&quot;">​</a></h3><p><strong>价值投资的问题：太长</strong></p><blockquote><p>&quot;价值投资从理论上看起来确实是一条一定能够通向成功的道路，但是这个道路最大的问题是太长。&quot;</p></blockquote><ul><li>也许你买的时候正好市场对公司内生价值完全不看好</li><li>你不知道什么时候市场能变得更加理性</li><li>公司本身的价值增长要靠很多很多方面</li><li>需要公司管理层上下不断地努力工作</li><li>一个公司的成功需要很多人、很多时间、不懈的努力，还需要一些运气</li></ul><p><strong>为什么大家走小道？</strong></p><blockquote><p>&quot;康庄大道非常慢。听起来能走到头，但实际上很慢。&quot;</p></blockquote><p>市场总是让你感觉到短期可以获利：</p><ul><li>短期的资产确确实实可以有巨大的变化</li><li>这会给你幻觉，让你想象在短期里可以获得巨大利益</li><li>所以你会倾向于把时间、精力、聪明才智放在短期的市场预测上</li></ul><p><strong>结果：</strong></p><blockquote><p>&quot;几乎所有的近道都变成了旁门左道。因为几乎所有以短期交易为目的的投资行为，如果时间足够长的话，最终要么就走入了死胡同，要么就进入了沼泽地。&quot;</p></blockquote><h3 id="成为优秀投资人的时间" tabindex="-1">成为优秀投资人的时间 <a class="header-anchor" href="#成为优秀投资人的时间" aria-label="Permalink to &quot;成为优秀投资人的时间&quot;">​</a></h3><blockquote><p>&quot;在这个行业里，要在很长时间持续不断地艰苦地工作，才有可能真正地成才，这个时间恐怕要15年以上。&quot;</p></blockquote><p>为什么是15年？</p><ul><li>市场可以连续15年达到14%的回报（你不需要做天才）</li><li>也可以连续十几年回报是负的（如果你这时候还优秀，就是能力）</li><li>连续15年以上保持优异成绩，才能判定是能力大于运气</li></ul><h2 id="第五部分-价值投资在中国是否适用" tabindex="-1">第五部分：价值投资在中国是否适用？ <a class="header-anchor" href="#第五部分-价值投资在中国是否适用" aria-label="Permalink to &quot;第五部分：价值投资在中国是否适用？&quot;">​</a></h2><h3 id="中国1991年以来的数据" tabindex="-1">中国1991年以来的数据 <a class="header-anchor" href="#中国1991年以来的数据" aria-label="Permalink to &quot;中国1991年以来的数据&quot;">​</a></h3><p>李录展示了中国过去20多年的数据：</p><table tabindex="0"><thead><tr><th>资产类别</th><th>1991年1元的购买力（2014年）</th></tr></thead><tbody><tr><td>现金</td><td>0.47元</td></tr><tr><td>黄金</td><td>类似</td></tr><tr><td>股票指数</td><td>持续增长</td></tr><tr><td>固定收益</td><td>基本增加</td></tr></tbody></table><p><strong>关键发现：</strong></p><blockquote><p>&quot;中国在过去20年里的模式几乎和美国过去200年是一模一样的。&quot;</p></blockquote><ul><li>基本模式相同</li><li>基本动力原因也是GDP的增长</li><li>由于中国GDP增长高于美国，股票增长价值的速度也更快</li></ul><h3 id="具体公司的表现" tabindex="-1">具体公司的表现 <a class="header-anchor" href="#具体公司的表现" aria-label="Permalink to &quot;具体公司的表现&quot;">​</a></h3><table tabindex="0"><thead><tr><th>公司</th><th>涨幅</th></tr></thead><tbody><tr><td>万科</td><td>1000多倍</td></tr><tr><td>格力</td><td>数百倍</td></tr><tr><td>福耀</td><td>数十倍</td></tr><tr><td>茅台</td><td>数百倍</td></tr><tr><td>腾讯（港股）</td><td>186倍（10年）</td></tr></tbody></table><p><strong>李录的观察：</strong></p><blockquote><p>&quot;股指不是一个抽象的东西，股指是由具体的一家家公司组成的。确确实实在过去200年我们走了好多不同的路，但是当我们选择3.0文明正道的时候会发现，中国表现出来的结果确实和其他3.0文明国家几乎是一样的。&quot;</p></blockquote><h3 id="中国会不会背离3-0文明" tabindex="-1">中国会不会背离3.0文明？ <a class="header-anchor" href="#中国会不会背离3-0文明" aria-label="Permalink to &quot;中国会不会背离3.0文明？&quot;">​</a></h3><p>这是投资人最担心的问题。</p><p><strong>李录的分析：</strong></p><ol><li><p><strong>中国已经尝到了现代化的甜头</strong></p><ul><li>过去35年经济快速增长</li><li>人民生活水平大幅提高</li><li>离开的成本非常高</li></ul></li><li><p><strong>3.0文明的铁律</strong></p><ul><li>最大的市场会成为唯一的市场</li><li>离开最大市场就会落后</li><li>中国不可能永远成为失败者</li></ul></li><li><p><strong>文化和历史因素</strong></p><ul><li>中国文化在经历了几千年的成功之后不愿意失败</li><li>任何短暂的离开、偏离3.0文明主轨的行为，很快就会被修正</li></ul></li></ol><p><strong>结论：</strong></p><blockquote><p>&quot;中国在未来二三十年里持续保持在全球市场里、持续进行自由市场经济和现代科学技术的情况是一个大概率事件。&quot;</p></blockquote><h3 id="中国市场的独特优势" tabindex="-1">中国市场的独特优势 <a class="header-anchor" href="#中国市场的独特优势" aria-label="Permalink to &quot;中国市场的独特优势&quot;">​</a></h3><p>李录认为，中国目前不成熟的阶段反而使价值投资人具备更多优势：</p><p><strong>优势一：散户为主的市场</strong></p><ul><li>资本市场70%仍然是散户</li><li>以短期交易为主</li><li>价格常常会大规模背离内在价值</li><li>产生非常独特的投资机会</li></ul><p><strong>优势二：竞争者更少</strong></p><ul><li>如果你不被短期交易所左右</li><li>真正坚持长期的价值投资</li><li>竞争者会更少，成功几率会更高</li></ul><p><strong>优势三：市场正在成熟化</strong></p><ul><li>金融市场扮演越来越重要的融资角色</li><li>规模、机构化程度、成熟度都会提高</li><li>真正的价值投资人会发挥越来越重要的作用</li></ul><h2 id="第六部分-常见误区与深度思考" tabindex="-1">第六部分：常见误区与深度思考 <a class="header-anchor" href="#第六部分-常见误区与深度思考" aria-label="Permalink to &quot;第六部分：常见误区与深度思考&quot;">​</a></h2><h3 id="误区一-价值投资太慢-不适合中国" tabindex="-1">误区一：价值投资太慢，不适合中国 <a class="header-anchor" href="#误区一-价值投资太慢-不适合中国" aria-label="Permalink to &quot;误区一：价值投资太慢，不适合中国&quot;">​</a></h3><p><strong>错误观点</strong>：中国股市波动大，价值投资太慢，应该做趋势、做短线。</p><p><strong>正确理解</strong>：</p><ul><li>短期波动是噪音，长期趋势是价值</li><li>正是因为大家追求短期，价值投资才有超额收益</li><li>中国市场的散户特性反而给价值投资者创造了机会</li></ul><p><strong>李录的观点</strong>：</p><blockquote><p>&quot;如果你不被短期交易所左右、所迷惑，真正坚持长期的价值投资，那么你的竞争者会更少，成功的几率会更高。&quot;</p></blockquote><h3 id="误区二-中国政策风险大-不能长期投资" tabindex="-1">误区二：中国政策风险大，不能长期投资 <a class="header-anchor" href="#误区二-中国政策风险大-不能长期投资" aria-label="Permalink to &quot;误区二：中国政策风险大，不能长期投资&quot;">​</a></h3><p><strong>错误观点</strong>：中国政策变化快，不适合长期持有。</p><p><strong>正确理解</strong>：</p><ul><li>政策会有波动，但3.0文明的大方向是确定的</li><li>中国离开全球市场的成本太高</li><li>短期波动反而创造了买入机会</li></ul><p><strong>安全边际的应用</strong>：</p><blockquote><p>&quot;当你这么认为的时候，你对3.0文明铁律的理解仍然可以让你在有足够安全边际的情况下进行价值投资。&quot;</p></blockquote><h3 id="误区三-价值投资就是买蓝筹股" tabindex="-1">误区三：价值投资就是买蓝筹股 <a class="header-anchor" href="#误区三-价值投资就是买蓝筹股" aria-label="Permalink to &quot;误区三：价值投资就是买蓝筹股&quot;">​</a></h3><p><strong>错误观点</strong>：价值投资就是买大白马、蓝筹股。</p><p><strong>正确理解</strong>：</p><ul><li>价值投资是买价格低于内在价值的股票</li><li>不一定是大盘股，也不一定是小盘股</li><li>关键是理解公司，确定内在价值</li></ul><p><strong>能力圈的重要性</strong>：</p><blockquote><p>&quot;你真正努力之后会发现在某一些公司里，在某一些行业里，你可以看得很清楚。&quot;</p></blockquote><h3 id="误区四-看过《证券分析》就是价值投资者" tabindex="-1">误区四：看过《证券分析》就是价值投资者 <a class="header-anchor" href="#误区四-看过《证券分析》就是价值投资者" aria-label="Permalink to &quot;误区四：看过《证券分析》就是价值投资者&quot;">​</a></h3><p><strong>错误观点</strong>：读过格雷厄姆、巴菲特的书，就掌握了价值投资。</p><p><strong>正确理解</strong>：</p><ul><li>价值投资需要长期实践</li><li>需要建立真正的能力圈</li><li>需要15年以上的持续努力</li></ul><p><strong>李录的提醒</strong>：</p><blockquote><p>&quot;坚持努力15年，一定可以成为优秀的投资人！&quot;</p></blockquote><h2 id="本章总结" tabindex="-1">本章总结 <a class="header-anchor" href="#本章总结" aria-label="Permalink to &quot;本章总结&quot;">​</a></h2><h3 id="核心要点回顾" tabindex="-1">核心要点回顾 <a class="header-anchor" href="#核心要点回顾" aria-label="Permalink to &quot;核心要点回顾&quot;">​</a></h3><ol><li><p><strong>资产管理行业的道德底线</strong>：追求真知、建立受托人责任</p></li><li><p><strong>200年数据揭示的真相</strong>：股票是长期最好的投资标的，年化回报约6.7%</p></li><li><p><strong>价值投资的四大理念</strong>：</p><ul><li>股票代表公司所有权</li><li>市场是为服务你而存在</li><li>安全边际</li><li>能力圈</li></ul></li><li><p><strong>为什么是大道的标准</strong>：得到的东西是应得的，可持续</p></li><li><p><strong>中国能实现价值投资</strong>：</p><ul><li>数据证明模式与美国相同</li><li>散户市场创造独特机会</li><li>3.0文明铁律决定大方向</li></ul></li><li><p><strong>成为优秀投资人的时间</strong>：15年以上持续努力</p></li></ol><h3 id="关键术语" tabindex="-1">关键术语 <a class="header-anchor" href="#关键术语" aria-label="Permalink to &quot;关键术语&quot;">​</a></h3><ul><li><strong>受托人责任（Fiduciary Duty）</strong>：把客户的钱当作自己父母的保命钱</li><li><strong>安全边际</strong>：买入价格大大低于内在价值</li><li><strong>能力圈</strong>：对某些公司、行业有超越常人的深刻理解</li><li><strong>3.0文明铁律</strong>：最大市场成为唯一市场，离开者落后</li><li><strong>正道 vs 邪道</strong>：创造价值 vs 零和游戏</li></ul><h3 id="延伸思考" tabindex="-1">延伸思考 <a class="header-anchor" href="#延伸思考" aria-label="Permalink to &quot;延伸思考&quot;">​</a></h3><ol><li><p><strong>如何检验自己是否有受托人责任的基因？</strong></p><ul><li>能否把客户利益放在自己利益之前？</li><li>能否在市场狂热时保持理性？</li></ul></li><li><p><strong>如何建立自己的能力圈？</strong></p><ul><li>从哪个行业开始？</li><li>需要多长时间？</li></ul></li><li><p><strong>在中国市场，哪些行业适合价值投资？</strong></p><ul><li>哪些公司具备长期竞争力？</li><li>如何识别？</li></ul></li><li><p><strong>15年的成才之路，如何坚持？</strong></p><ul><li>遇到连续亏损怎么办？</li><li>如何保持初心？</li></ul></li></ol><h3 id="下章预告" tabindex="-1">下章预告 <a class="header-anchor" href="#下章预告" aria-label="Permalink to &quot;下章预告&quot;">​</a></h3><p>下一章我们将探讨：<strong>《价值投资的知行合一》</strong>——李录2019年北大演讲，如何在实践中真正做到价值投资？知与行之间有什么鸿沟？</p><hr><p><em>本文基于李录2015年10月在北京大学光华管理学院的演讲《价值投资在中国的展望》整理，结合投资实践进行深度解读。</em></p>',160)])])}const g=l(r,[["render",e]]);export{q as __pageData,g as default};
